48	void apply_repetition_penalties_(
49	    torch::Tensor& logits,             // [num_seqs, vocab_size], in-place
50	    const torch::Tensor& prompt_mask,  // [num_seqs, vocab_size]
51	    const torch::Tensor& output_mask,  // [num_seqs, vocab_size]
52	    const torch::Tensor& repetition_penalties) {  // [num_seqs]
53	  TORCH_CHECK(logits.is_contiguous());
54	  TORCH_CHECK(prompt_mask.is_contiguous());
55	  TORCH_CHECK(output_mask.is_contiguous());
56	  TORCH_CHECK(repetition_penalties.is_contiguous());
57	
58	  int vocab_size = logits.size(-1);
59	  int num_seqs = logits.size(0);
60	
61	  if (num_seqs == 0) return;
62	
63	  // Get number of SMs on the current device
64	  int sms = 0;
65	  cudaDeviceGetAttribute(&sms, cudaDevAttrMultiProcessorCount,
66	                         logits.get_device());
67	
68	  // Compute tile_num and tile_size
69	  int tile_num =
70	      std::min(vocab_size, std::max(1, (sms + num_seqs - 1) / num_seqs));
71	  int tile_size = (vocab_size + tile_num - 1) / tile_num;
72	
73	  // Each block handles one sequence and a tile of vocab
74	  dim3 grid(num_seqs, tile_num);
75	  dim3 block(std::min(tile_size, 1024));
76	  const at::cuda::OptionalCUDAGuard device_guard(device_of(logits));
77	  const cudaStream_t stream = at::cuda::getCurrentCUDAStream();
78	  VLLM_DISPATCH_FLOATING_TYPES(
79	      logits.scalar_type(), "apply_repetition_penalties_kernel", [&] {
80	        vllm::apply_repetition_penalties_kernel<scalar_t>
81	            <<<grid, block, 0, stream>>>(
82	                logits.data_ptr<scalar_t>(), prompt_mask.data_ptr<bool>(),
83	                output_mask.data_ptr<bool>(),
84	                repetition_penalties.data_ptr<scalar_t>(), num_seqs, vocab_size,
85	                tile_size);
86	      });
87	}

